import java.io.*;

public class App {
    // Version 1: handles internally
    static String loadConfigCatch(String name) {
        try {
            if (name.startsWith("missing")) throw new IOException(name + " unavailable");
            return "Config loaded: " + name;
        } catch (IOException e) {
            return "Config load failed, using defaults";
        }
    }

    // Version 2: propagates to caller
    static String loadConfigThrows(String name) throws IOException {
        if (name.startsWith("missing")) throw new IOException(name + " unavailable");
        return "Config loaded: " + name;
    }

    public static void main(String[] args) {
        System.out.println("Version 1: " + loadConfigCatch("missing.cfg"));

        try {
            System.out.println("Version 2: " + loadConfigThrows("missing.cfg"));
        } catch (IOException e) {
            System.out.println("Version 2: caught in main: " + e.getMessage());
        }
    }
}

