import java.io.*;

public class App {
    // Only needs to declare checked IOException
    static void processPayment(String amountStr, String filePath) throws IOException {
        double amount = Double.parseDouble(amountStr);  // NumberFormatException — unchecked
        // Simulate file write
        if (filePath.contains("bad")) throw new IOException(filePath + " write failed");
        System.out.println("₹" + amount + " logged to " + filePath);
    }

    public static void main(String[] args) {
        // Success case
        try {
            processPayment("5000", "payments.log");
        } catch (IOException e) {
            System.out.println("IOException caught: " + e.getMessage());
        }

        // NumberFormatException (unchecked — can catch or not)
        try {
            processPayment("abc", "payments.log");
        } catch (NumberFormatException e) {
            System.out.println("NumberFormatException caught: " + e.getMessage());
        } catch (IOException e) {
            System.out.println("IOException caught: " + e.getMessage());
        }

        // IOException
        try {
            processPayment("1000", "payments-bad.log");
        } catch (NumberFormatException e) {
            System.out.println("NumberFormatException caught: " + e.getMessage());
        } catch (IOException e) {
            System.out.println("IOException caught: " + e.getMessage());
        }
    }
}

class SQLException extends Exception {
    public SQLException(String msg) { super(msg); }
}

class DataAccessException extends RuntimeException {
    public DataAccessException(String msg, Throwable cause) { super(msg, cause); }
}

class DataRepository {
    static String findUser(int id) throws SQLException {
        if (id < 0) throw new SQLException("negative id");
        return id == 1 ? "Aisha" : "Unknown";
    }
}

class UserService {
    // No throws — wraps checked in unchecked
    static String getUser(int id) {
        try {
            return "User found: " + DataRepository.findUser(id);
        } catch (SQLException e) {
            throw new DataAccessException("Database error for id=" + id, e);
        }
    }
}

public class App {
    public static void main(String[] args) {
        System.out.println(UserService.getUser(1));

        try {
            System.out.println(UserService.getUser(-1));
        } catch (DataAccessException e) {
            System.out.println("DataAccessException: " + e.getMessage() +
                " — caused by: " + e.getCause().getMessage());
        }
    }
}

