import java.io.*;

public class App {
    static void process(String source) throws IOException {
        if (source.equals("missing.txt")) {
            throw new FileNotFoundException(source + " (No such file or directory)");
        } else if (source.equals("network")) {
            throw new IOException("network error");
        }
    }

    public static void main(String[] args) {
        String[] sources = {"missing.txt", "network"};
        for (String s : sources) {
            try {
                process(s);
            } catch (IOException e) {
                if (e instanceof FileNotFoundException fnfe) {
                    System.out.println("FileNotFoundException: " + fnfe.getMessage());
                } else {
                    System.out.println("General IOException: " + e.getMessage());
                }
            }
        }
    }
}

class ProcessingException extends Exception {
    ProcessingException(String step, String msg) {
        super(step + ": " + msg);
    }
}

class Importer {
    static void validate(String record) throws ProcessingException {
        if (record.startsWith("NONAME")) throw new ProcessingException("validation", "Name required");
    }

    static void parse(String record) throws ProcessingException {
        if (record.contains("BADDATE")) throw new ProcessingException("parsing", "Invalid date format");
    }

    static void save(String record) throws ProcessingException {
        // Simulate save — no failures here
    }

    static String importRecord(String record) throws ProcessingException {
        validate(record);
        parse(record);
        save(record);
        return "imported";
    }
}

public class App {
    public static void main(String[] args) {
        String[] records = {"Aisha,2024-01-15,₹5000", "NONAME,2024-01-16,₹3000", "Raj,BADDATE,₹2000"};

        for (int i = 0; i < records.length; i++) {
            try {
                String result = Importer.importRecord(records[i]);
                System.out.println("Record " + (i + 1) + ": " + result);
            } catch (ProcessingException e) {
                System.out.println("Record " + (i + 1) + ": FAILED — " + e.getMessage());
            }
        }
    }
}

import java.util.*;

class BookUnavailableException extends Exception {
    BookUnavailableException(String msg) { super(msg); }
}

class Book {
    String isbn, title;
    boolean checkedOut;
    Book(String isbn, String title) { this.isbn = isbn; this.title = title; }
}

class BookLibrary {
    private Map<String, Book> books = new HashMap<>();

    public void addBook(Book book) {
        if (book == null) throw new IllegalArgumentException("Book cannot be null");
        if (books.containsKey(book.isbn)) throw new IllegalArgumentException("Duplicate ISBN: " + book.isbn);
        books.put(book.isbn, book);
        System.out.println("Added: " + book.title + " (" + book.isbn + ")");
    }

    public void checkout(String isbn, String patron) throws BookUnavailableException {
        Book b = books.get(isbn);
        if (b == null)          throw new BookUnavailableException(isbn + " not found");
        if (b.checkedOut)       throw new BookUnavailableException(isbn + " is already checked out");
        b.checkedOut = true;
        System.out.println("Checked out: " + b.title + " to " + patron);
    }

    public Book getBook(String isbn) {
        if (isbn == null) throw new IllegalArgumentException("ISBN cannot be null");
        return books.get(isbn);
    }
}

public class App {
    public static void main(String[] args) {
        BookLibrary lib = new BookLibrary();
        lib.addBook(new Book("ISBN-001", "Clean Code"));

        try { lib.addBook(null); }
        catch (IllegalArgumentException e) { System.out.println("IllegalArgumentException: " + e.getMessage()); }

        try {
            lib.checkout("ISBN-001", "Aisha");
            lib.checkout("ISBN-001", "Raj");  // already checked out
        } catch (BookUnavailableException e) {
            System.out.println("BookUnavailableException: " + e.getMessage());
        }

        Book found = lib.getBook("ISBN-001");
        System.out.println("Found: " + (found != null ? found.title : "null"));
    }
}

class QueryException extends Exception {
    QueryException(String msg) { super(msg); }
}

class DAOException extends RuntimeException {
    DAOException(String msg, Throwable cause) { super(msg, cause); }
}

class QueryRunner {
    static String execute(String sql) throws QueryException {
        if (sql.contains("BADUSER")) throw new QueryException("Simulated: record not found");
        if (sql.contains("Aisha"))  return "User[Aisha,aisha@x.com]";
        return null;
    }
}

class UserDAO {
    static String findByName(String name) {
        String sql = "SELECT * FROM users WHERE name='" + name + "'";
        try {
            return QueryRunner.execute(sql);
        } catch (QueryException e) {
            throw new DAOException("DAO failed for query: name='" + name + "'", e);
        }
    }
}

class UserService {
    // No try-catch needed — DAOException is unchecked
    static String lookupUser(String name) {
        String result = UserDAO.findByName(name);
        return result != null ? "Found: " + result : "Not found: " + name;
    }
}

public class App {
    public static void main(String[] args) {
        System.out.println(UserService.lookupUser("Aisha"));

        try {
            System.out.println(UserService.lookupUser("BADUSER"));
        } catch (DAOException e) {
            System.out.println("DAOException: " + e.getMessage() + " — " + e.getCause().getMessage());
        }
    }
}

import java.util.*;

class PaymentException extends Exception {
    PaymentException(String msg) { super(msg); }
}

class InsufficientFundsException extends PaymentException {
    final String accountId;
    final double available, attempted;
    InsufficientFundsException(String accountId, double available, double attempted) {
        super(accountId + " has ₹" + available + ", needed ₹" + attempted);
        this.accountId = accountId; this.available = available; this.attempted = attempted;
    }
}

class InvalidPaymentException extends RuntimeException {
    InvalidPaymentException(String msg) { super(msg); }
}

class InvalidAmountException extends InvalidPaymentException {
    InvalidAmountException(double amount) {
        super("Amount must be positive, got: " + amount);
    }
}

class InvalidAccountException extends InvalidPaymentException {
    InvalidAccountException(String id) { super("Account not found: " + id); }
}

class PaymentProcessor {
    private Map<String, Double> accounts = new HashMap<>();

    PaymentProcessor() {
        accounts.put("A001", 5000.0);
        accounts.put("A002", 2000.0);
    }

    void transfer(String from, String to, double amount) throws PaymentException {
        if (amount <= 0) throw new InvalidAmountException(amount);
        if (!accounts.containsKey(from)) throw new InvalidAccountException(from);
        if (!accounts.containsKey(to))   throw new InvalidAccountException(to);

        double balance = accounts.get(from);
        if (balance < amount) throw new InsufficientFundsException(from, balance, amount);

        accounts.put(from, balance - amount);
        accounts.put(to, accounts.get(to) + amount);
        System.out.println("Transferred ₹" + amount + ": " + from + "→" + to);
    }
}

public class App {
    public static void main(String[] args) {
        PaymentProcessor pp = new PaymentProcessor();

        // Success
        try { pp.transfer("A001", "A002", 1000); } 
        catch (PaymentException e) { System.out.println(e.getClass().getSimpleName() + ": " + e.getMessage()); }

        // Invalid amount
        try { pp.transfer("A001", "A002", -500); }
        catch (InvalidAmountException e) { System.out.println("InvalidAmountException: " + e.getMessage()); }

        // Invalid account
        try { pp.transfer("A999", "A002", 100); }
        catch (InvalidAccountException e) { System.out.println("InvalidAccountException: " + e.getMessage()); }

        // Insufficient funds
        try { pp.transfer("A001", "A002", 5000); }  // A001 has 4000 now
        catch (InsufficientFundsException e) { System.out.println("InsufficientFundsException: " + e.getMessage()); }
        catch (PaymentException e) { System.out.println(e.getMessage()); }
    }
}
